// src/components/CartItem/index.jsx
import React from 'react';
import { useDispatch } from 'react-redux';
import { increaseCount, decreaseCount, removeFromCart } from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/fixUrl';
import s from './CartItem.module.css';

const CartItem = ({ item }) => {
  const dispatch = useDispatch();
  const imageUrl = getImageUrl(item.image);

  // Обработчики
  const handleIncrease = () => dispatch(increaseCount({ id: item.id }));
  const handleDecrease = () => dispatch(decreaseCount({ id: item.id }));
  const handleRemove = () => dispatch(removeFromCart({ id: item.id }));

  // 🚀 БЕЗОПАСНЫЙ РАСЧЕТ ЦЕН
  // Используем 0 как запасное значение, если цена undefined или null
  const price = item.price || 0;
  const discontPrice = item.discont_price || 0;

  // Определяем финальную цену (со скидкой или без)
  const finalPrice = discontPrice > 0 ? discontPrice : price;

  // Форматирование цен
  const unitPrice = finalPrice.toFixed(2);
  const itemTotalPrice = (finalPrice * item.count).toFixed(2);

  // Определяем, нужно ли показывать зачеркнутую цену
  const originalPrice = (discontPrice > 0 && price > discontPrice) 
    ? price.toFixed(2) 
    : null;

  return (
    <div className={s.item}>
      <img src={imageUrl} alt={item.title} className={s.image} />

      <div className={s.details}>
        <h3 className={s.title}>{item.title}</h3>

        <div className={s.controls}>
          <button className={s.removeButton} onClick={handleRemove}>
             X 
          </button>

          {/* Контроль количества */}
          <div className={s.quantity}>
            <button onClick={handleDecrease} disabled={item.count <= 1}>-</button>
            <span className={s.count}>{item.count}</span>
            <button onClick={handleIncrease}>+</button>
          </div>
        </div>
      </div>

      <div className={s.priceBlock}>
          {/* Цена до скидки (зачеркнутая) */}
          {originalPrice && <p className={s.originalPrice}>{originalPrice} $</p>}

          {/* Общая цена за позицию */}
          <p className={s.totalPrice}>{itemTotalPrice} $</p>

          {/* Цена за единицу (подробно) */}
          <p className={s.unitPrice}>{unitPrice} $ / шт.</p>
      </div>
    </div>
  );
};

export default CartItem;
